package com.hospital.management.util;import com.hospital.management.model.*;import javax.servlet.http.*;
public final class RequestUtil{private RequestUtil(){}public static AuditContext buildAuditContext(HttpServletRequest r){AuthenticatedUser u=(AuthenticatedUser)r.getSession(false).getAttribute("authenticatedUser");return new AuditContext(u.getUserId(),getClientIpAddress(r),r.getHeader("User-Agent"));}public static String getClientIpAddress(HttpServletRequest r){String f=r.getHeader("X-Forwarded-For");if(f!=null&&!f.isBlank()){String first=f.split(",",2)[0].trim();if(first.matches("[0-9a-fA-F:.]{3,45}"))return first;}return r.getRemoteAddr();}}
